using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private const string ModelPath = "Data/model.zip";

    public static string TrainAndSaveModel(ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Combine text features and the numeric Priority into a single feature vector
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("  MicroAccuracy:     {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("  MacroAccuracy:     {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("  LogLoss:           {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("  LogLossReduction:  {LogLossReduction:F4}", metrics.LogLossReduction);

        var modelSavePath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(model, split.TrainSet.Schema, modelSavePath);
        logger.LogInformation("Model saved to {Path}", modelSavePath);

        return modelSavePath;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketPrediction> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionPool.Predict(input);

        return Ok(prediction);
    }
}

